const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth    = headers['authorization'] || headers['Authorization'] || '';
const token   = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };

const action = String(body.action || '').toLowerCase().trim();
const allowed = ['load_template', 'start_draft', 'save_step', 'submit'];
if (allowed.indexOf(action) === -1) {
  return { json: { ok: false, status: 400, error: 'Unknown action: ' + (body.action || '(missing)') } };
}

function safeInt(v, def) { const n = parseInt(v, 10); return isNaN(n) ? def : n; }

return { json: {
  token: token,
  action: action,
  industry_slug: String(body.industry_slug || '').trim() || null,
  draft_id:      body.draft_id || null,
  answers:       body.answers && typeof body.answers === 'object' ? body.answers : {},
  email:         body.email || null,
  full_name:     body.full_name || null,
  company:       body.company || null,
  phone:         body.phone || null,
  step:          safeInt(body.step, 0),
  addons:        Array.isArray(body.addons) ? body.addons : [],
  preview_monthly_cents: safeInt(body.preview_monthly_cents, 0),
  preview_total_cents:   safeInt(body.preview_total_cents, 0),
  preview_one_time_cents: safeInt(body.preview_one_time_cents, 0)
} };

const rows = $input.item.json;
const row  = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
const x = $('Extract Inputs').item.json;
return { json: Object.assign({ ok: true }, x) };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const tpls    = allOf('Get Template');
const rules   = allOf('Get Pricing Rules');
const addons  = allOf('Get Addons');
if (tpls.length === 0) {
  return { json: { ok: false, status: 404, error: 'Template not found' } };
}
return { json: {
  ok: true,
  template: tpls[0],
  pricing_rules: rules,
  addons: addons
} };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const tpls = allOf('Resolve Template Id (start)');
if (tpls.length === 0) return { json: { ok: false, status: 404, error: 'Template not found for industry_slug' } };
const x = $('Check Admin').item.json;
// Resume tokens: 32-hex random; used to reopen a draft from an emailed link.
function tok() {
  let s = '';
  for (let i = 0; i < 32; i++) s += Math.floor(Math.random() * 16).toString(16);
  return s;
}
return { json: {
  body: {
    template_id:   tpls[0].id,
    industry_slug: x.industry_slug,
    email:         x.email,
    full_name:     x.full_name,
    company:       x.company,
    phone:         x.phone,
    answers:       x.answers || {},
    step:          0,
    status:        'in_progress',
    resume_token:  tok()
  }
} };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const rows = allOf('Insert Draft');
if (rows.length === 0) return { json: { ok: false, status: 500, error: 'Failed to insert quote draft' } };
const d = rows[0];
return { json: {
  ok: true,
  draft_id:     d.id,
  resume_token: d.resume_token,
  industry_slug:d.industry_slug,
  step:         d.step || 0,
  status:       d.status,
  created_at:   d.created_at
} };

// Build a PATCH body for the existing draft. Stores answers + the
// page's locally-computed preview values for fast list-page rendering.
// SUBMIT will recompute authoritatively before producing a final quote.
const x = $('Check Admin').item.json;
if (!x.draft_id) return { json: { ok: false, status: 400, error: 'save_step requires draft_id' } };
return { json: {
  draft_id: x.draft_id,
  body: {
    answers:               x.answers || {},
    step:                  x.step,
    email:                 x.email,
    full_name:             x.full_name,
    company:               x.company,
    phone:                 x.phone,
    preview_monthly_cents: x.preview_monthly_cents,
    preview_total_cents:   x.preview_total_cents,
    preview_one_time_cents:x.preview_one_time_cents
  }
} };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const rows = allOf('Patch Draft');
if (rows.length === 0) return { json: { ok: false, status: 404, error: 'Draft not found' } };
const d = rows[0];
return { json: {
  ok: true,
  draft_id:               d.id,
  step:                   d.step,
  preview_monthly_cents:  d.preview_monthly_cents,
  preview_total_cents:    d.preview_total_cents,
  preview_one_time_cents: d.preview_one_time_cents,
  updated_at:             d.updated_at
} };

// Authoritative server-side pricing. Refuses to trust the client's
// preview_*_cents values; recomputes from template + rules + addons.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};

const drafts    = allOf('Get Draft (submit)');
const templates = allOf('Get Template (submit)');
const rules     = allOf('Get Rules (submit)');
const addons    = allOf('Get Addons (submit)');
const inputs    = $('Check Admin').item.json;

if (drafts.length === 0)    return { json: { ok: false, status: 404, error: 'Draft not found' } };
if (templates.length === 0) return { json: { ok: false, status: 404, error: 'Template not found' } };

const draft    = drafts[0];
const template = templates[0];
const answers  = draft.answers || {};

// Industry-agnostic tier picker: start at starter base, sum rule
// adjustments, then label-tier based on where adjusted monthly
// lands relative to growth + scale bases. Same logic as the
// client-side pickTier in industry.html (kept in sync).
const baseMonthly = template.base_starter_cents || 0;

function evalCondition(conds, ans) {
  if (!conds || typeof conds !== 'object') return true;
  const keys = Object.keys(conds);
  for (let i = 0; i < keys.length; i++) {
    const k = keys[i];
    const rule = conds[k];
    if (!rule || typeof rule !== 'object') continue;
    const actual = ans[k];
    const op = (rule.op || 'eq').toLowerCase();
    const val = rule.value;
    if (actual == null) return false;
    if (op === 'eq'  && actual !== val) return false;
    if (op === 'neq' && actual === val) return false;
    if (op === 'lt'  && !(actual <  val)) return false;
    if (op === 'lte' && !(actual <= val)) return false;
    if (op === 'gt'  && !(actual >  val)) return false;
    if (op === 'gte' && !(actual >= val)) return false;
    if (op === 'between' && Array.isArray(val) && (actual < val[0] || actual > val[1])) return false;
    if (op === 'in'  && Array.isArray(val) && val.indexOf(actual) === -1) return false;
  }
  return true;
}

const rulesApplied = [];
let adjustCents = 0;
rules.forEach(function (r) {
  if (!evalCondition(r.conditions, answers)) return;
  const pctAdjust = Math.round(baseMonthly * (parseFloat(r.adjust_percent) || 0) / 100);
  const total = (r.adjust_cents || 0) + pctAdjust;
  adjustCents += total;
  rulesApplied.push({ rule_id: r.id, rule_name: r.rule_name, adjust_cents: total, adjust_percent: parseFloat(r.adjust_percent) || 0 });
});

// Selected addons come from the request body (Check Admin -> inputs.addons)
const selectedAddonIds = (inputs.addons || []).map(function (a) { return typeof a === 'string' ? a : a.id; });
const addonsSelected = [];
let addonsMonthly  = 0;
let addonsOneTime  = 0;
addons.forEach(function (a) {
  if (selectedAddonIds.indexOf(a.id) === -1) return;
  addonsMonthly  += (a.monthly_cents  || 0);
  addonsOneTime  += (a.one_time_cents || 0);
  addonsSelected.push({ addon_id: a.id, addon_slug: a.addon_slug, addon_name: a.addon_name, monthly_cents: a.monthly_cents, one_time_cents: a.one_time_cents });
});

const adjustedMonthly = baseMonthly + adjustCents;
const starterBase = template.base_starter_cents || 0;
const growthBase  = template.base_growth_cents  || 0;
const scaleBase   = template.base_scale_cents   || 0;
let tier = 'starter';
if (scaleBase  && adjustedMonthly >= (growthBase + scaleBase) / 2) tier = 'scale';
else if (growthBase && adjustedMonthly >= (starterBase + growthBase) / 2) tier = 'growth';
const totalMonthly  = adjustedMonthly + addonsMonthly;
const totalFirstYear = totalMonthly * 12 + addonsOneTime;

return { json: {
  draft:           draft,
  template:        template,
  insert_body: {
    draft_id:               draft.id,
    template_id:            template.id,
    industry_slug:          template.industry_slug,
    client_id:              draft.client_id,
    lead_id:                draft.lead_id,
    email:                  draft.email || inputs.email,
    full_name:              draft.full_name || inputs.full_name,
    company:                draft.company || inputs.company,
    phone:                  draft.phone || inputs.phone,
    answers_snapshot:       answers,
    rules_applied:          rulesApplied,
    addons_selected:        addonsSelected,
    base_tier:              tier,
    base_monthly_cents:     baseMonthly,
    total_monthly_cents:    totalMonthly,
    total_one_time_cents:   addonsOneTime,
    total_first_year_cents: totalFirstYear,
    status:                 'open',
    expires_at:             new Date(Date.now() + 30 * 86400000).toISOString()  // 30 day default
  }
} };

