    { quote_id: qid, step: 1, scheduled_at: new Date(now +  3 * 86400000).toISOString(), status: 'pending', message_template: 'check-in' },
    { quote_id: qid, step: 2, scheduled_at: new Date(now +  7 * 86400000).toISOString(), status: 'pending', message_template: 'value-reinforce' },
    { quote_id: qid, step: 3, scheduled_at: new Date(now + 14 * 86400000).toISOString(), status: 'pending', message_template: 'final-nudge' }
  ];
})()) }}

