// Build the customer-facing quote email. Inline HTML; Postmark
// doesn't need a pre-registered template for this.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};

const rows = allOf('Insert Quote Completed');
if (rows.length === 0) return { json: { ok: false, status: 500, error: 'Quote insert returned no row' } };
const quote = rows[0];
const computed = $('Compute Quote').first().json;
const template = computed.template;

const fmtMoney = function (cents) {
  const v = (parseInt(cents, 10) || 0) / 100;
  return '$' + v.toLocaleString('en-CA', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
};

const rulesList = (quote.rules_applied || []).filter(function (r) { return r.adjust_cents || r.adjust_percent; })
  .map(function (r) { return '<li>' + r.rule_name + ': ' + (r.adjust_cents >= 0 ? '+' : '') + fmtMoney(r.adjust_cents) + '/mo</li>'; })
  .join('');
const addonsList = (quote.addons_selected || [])
  .map(function (a) { return '<li>' + a.addon_name + '. ' + fmtMoney(a.monthly_cents) + '/mo' + (a.one_time_cents > 0 ? ' + ' + fmtMoney(a.one_time_cents) + ' setup' : '') + '</li>'; })
  .join('');

const html =
  '<div style="font-family:Arial,Helvetica,sans-serif;font-size:15px;line-height:1.6;color:#333;max-width:640px">' +
  '<p>Hi ' + (quote.full_name || 'there') + ',</p>' +
  '<p>Here is your personalized Crystallux quote for <strong>' + (template.industry_name || quote.industry_slug) + '</strong>. ' +
  'It is valid for 30 days from today.</p>' +
  '<div style="background:#f8f7ff;border-left:4px solid #7C3AED;padding:18px 22px;margin:18px 0;border-radius:6px">' +
    '<div style="font-size:12px;color:#71717a;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px">Monthly Estimate</div>' +
    '<div style="font-size:32px;font-weight:700;color:#5B21B6">' + fmtMoney(quote.total_monthly_cents) + ' <span style="font-size:14px;color:#71717a;font-weight:400">/mo</span></div>' +
    '<div style="font-size:13px;color:#52525b;margin-top:4px">First-year all-in: <strong>' + fmtMoney(quote.total_first_year_cents) + '</strong> · ' + (quote.base_tier || 'starter') + ' tier</div>' +
  '</div>' +
  '<p><strong>Breakdown</strong></p>' +
  '<ul style="padding-left:20px">' +
    '<li>Base (' + (quote.base_tier || 'starter') + '): ' + fmtMoney(quote.base_monthly_cents) + '/mo</li>' +
    rulesList +
    (addonsList ? '<li><strong>Add-ons:</strong></li><ul>' + addonsList + '</ul>' : '') +
  '</ul>' +
  '<p style="margin-top:24px">Review and accept the quote at <a href="https://crystallux.org/quote/' + quote.id + '" style="color:#7C3AED;font-weight:600">crystallux.org/quote/' + quote.id + '</a>, or just reply to this email to schedule a 15-minute call.</p>' +
  '<p>Talk soon,<br><strong>Mary Akintunde · Crystallux</strong></p>' +
  '</div>';

return { json: {
  quote: quote,
  postmark_body: {
    From: 'info@crystallux.org',
    To: quote.email,
    Subject: 'Your Crystallux quote. ' + (template.industry_name || quote.industry_slug),
    HtmlBody: html,
    MessageStream: 'outbound',
    Tag: 'smart-quote',
    Metadata: { quote_id: quote.id, template_id: quote.template_id, industry_slug: quote.industry_slug }
  }
} };

const postmark = $input.item.json;
const quote    = $('Build Email').first().json.quote;
const sentOk   = !!(postmark && postmark.MessageID);

// Best-effort email log (mirrors what clx-email-send.json writes).
// We don't fail the submit if email send hits an issue. the quote
// is already persisted and Mary can resend manually.
return { json: {
  ok: true,
  quote_id:        quote.id,
  status:          quote.status,
  base_tier:       quote.base_tier,
  total_monthly_cents:    quote.total_monthly_cents,
  total_first_year_cents: quote.total_first_year_cents,
  email_sent:      sentOk,
  postmark_message_id: postmark && postmark.MessageID || null,
  postmark_error:  postmark && postmark.ErrorCode ? postmark.Message : null
} };
